-- ============================================================
-- Si Cantina Sociale — Historical daily sales
-- Migration: 006_historical_sales.sql
--
-- One row per calendar day. Used for year-on-year comparison
-- and revenue forecasting.
--
-- sale_date has a unique constraint — re-uploading the same
-- date simply updates the gross_sales figure (upsert semantics).
-- ============================================================

create table if not exists historical_sales (
  id          uuid          primary key default gen_random_uuid(),
  sale_date   date          not null unique,
  gross_sales numeric(12,2) not null check (gross_sales >= 0),
  notes       text,
  created_at  timestamptz   not null default now(),
  updated_at  timestamptz   not null default now()
);

-- Fast range lookups ordered newest-first
create index if not exists idx_historical_sales_date
  on historical_sales (sale_date desc);

